// Extract data from Whapi.cloud webhook payload
const body = $input.first().json.body || $input.first().json;

// Whapi sends a messages array
const messages = body.messages || [];

if (messages.length === 0) {
  return [{ json: { skip: true, phone: '', name: '', messageText: '', fromMe: true, messageType: 'unknown' } }];
}

const msg = messages[0];

// Extract phone number (remove @s.whatsapp.net if present)
const rawPhone = msg.chatId || msg.from || '';
const phone = rawPhone.replace('@s.whatsapp.net', '').replace('@c.us', '');

return [{
  json: {
    skip: false,
    phone: phone,
    name: msg.pushName || msg.senderName || 'Unknown',
    messageText: msg.body || (msg.text && msg.text.body) || '',
    fromMe: msg.fromMe === true,
    messageType: msg.type || 'unknown',
    messageId: msg.id || '',
    timestamp: new Date().toISOString()
  }
}];

// Get data from earlier nodes
const msgData = $('Is Text From Customer?').first().json;
const historyRows = $input.all();

// Build conversation history string from Google Sheets rows
let historyText = '';
for (const row of historyRows) {
  if (row.json.Role && row.json.Message) {
    const label = row.json.Role === 'user' ? msgData.name : 'Assistant';
    historyText += `${label}: ${row.json.Message}\n`;
  }
}

// ✏️ CUSTOMISE THIS SYSTEM PROMPT for your business
const systemPrompt = `You are a friendly and professional real estate assistant available 24/7. Your job is to:
- Welcome potential buyers/renters warmly
- Understand their property needs (location, budget, type, size)
- Answer questions about available properties
- Collect their contact info naturally during conversation
- Offer to schedule property viewings
- Keep responses short and conversational (2-4 sentences max)
- Always reply in the SAME LANGUAGE the customer writes in

Customer name: ${msgData.name}
Customer phone: ${msgData.phone}`;

const fullPrompt = `${systemPrompt}

--- Conversation History ---
${historyText || '(This is the first message)'}---

${msgData.name}: ${msgData.messageText}
Assistant:`;

return [{
  json: {
    ...msgData,
    prompt: fullPrompt
  }
}];
